	"public/main.ts": "// Boot the SPA. Both gen barrels:\n//   _vyn.client.gen.ts → registers every *.component.ts under public/\n//   _vyn.gen.ts        → routes table (HTML views + lazy controllers)\n\nimport \"../_vyn.client.gen.ts\";\nimport { createRouter } from \"@vynjs/client\";\nimport { routes } from \"../_vyn.gen.ts\";\n\ncreateRouter({\n\tmount: \"#app\",\n\troutes: [...routes],\n\tnotFound:\n\t\t'<section class=\"card\"><header class=\"card-head\"><h2>404 — Not found</h2><p class=\"hint\">No route matched. <a href=\"/\">Go home →</a></p></header></section>',\n});\n",
